# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import sys
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, NewPartitions
import argparse

def create_topics(admin_client, topics_config):
    topics = []
    for topic_config in topics_config:
        topic_name, partitions, replication_factor, config = topic_config
        topic = NewTopic(
            name=topic_name,
            num_partitions=partitions,
            replication_factor=replication_factor,
            topic_configs=config
        )
        topics.append(topic)
    
    try:
        result = admin_client.create_topics(topics, validate_only=False)
        print("Topics created successfully:", result)
    except Exception as e:
        print("Error creating topics:", e)

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Topics:", topics)
    except Exception as e:
        print("Error listing topics:", e)

def delete_topics(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topic_names)
        print("Topics deleted successfully:", result)
    except Exception as e:
        print("Error deleting topics:", e)

def describe_topics(admin_client, topic_names):
    try:
        topics = admin_client.describe_topics(topic_names)
        for topic in topics:
            print(f"Topic: {topic['topic']}")
            print(f"Partitions: {topic['partitions']}")
            print(f"Config: {topic['topic_configs']}")
    except Exception as e:
        print("Error describing topics:", e)

def add_partitions(admin_client, topic_partitions):
    partitions = []
    for topic_name, new_partition_count in topic_partitions:
        partition = NewPartitions(
            topic=topic_name,
            count=new_partition_count
        )
        partitions.append(partition)
    
    try:
        result = admin_client.create_partitions(partitions)
        print("Partitions added successfully:", result)
    except Exception as e:
        print("Error adding partitions:", e)

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', required=True, choices=['create', 'list', 'delete', 'describe', 'add-partitions'])
    parser.add_argument('--topics', nargs='*', help='Topic names')
    parser.add_argument('--partitions', type=int, help='Number of partitions')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
    parser.add_argument('--config', nargs='*', help='Topic configuration key=value pairs')
    parser.add_argument('--new-partitions', nargs='*', help='Topic name and new partition count')
    
    args = parser.parse_args()
    
    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
    
    if args.action == 'create':
        if not args.topics:
            print("Error: Topics required for create action")
            sys.exit(1)
        
        config_dict = {}
        if args.config:
            for config in args.config:
                key, value = config.split('=')
                config_dict[key] = value
        
        topics_config = []
        for topic in args.topics:
            topics_config.append((topic, args.partitions, args.replication_factor, config_dict))
        
        create_topics(admin_client, topics_config)
    
    elif args.action == 'list':
        list_topics(admin_client)
    
    elif args.action == 'delete':
        if not args.topics:
            print("Error: Topics required for delete action")
            sys.exit(1)
        delete_topics(admin_client, args.topics)
    
    elif args.action == 'describe':
        if not args.topics:
            print("Error: Topics required for describe action")
            sys.exit(1)
        describe_topics(admin_client, args.topics)
    
    elif args.action == 'add-partitions':
        if not args.new_partitions:
            print("Error: New partitions required for add-partitions action")
            sys.exit(1)
        
        topic_partitions = []
        for item in args.new_partitions:
            topic, partitions = item.split(':')
            topic_partitions.append((topic, int(partitions)))
        
        add_partitions(admin_client, topic_partitions)

if __name__ == '__main__':
    main()